1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Array<Damage> };
5	type Step = { op: string; items?: Array<Item>; policy?: number; incident?: Incident };
6	type Scenario = { customer?: Customer; steps: Array<Step> };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT_RATE = 0.15;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const INSURANCE_VALUES: Record<string, number> = {
29	  sword: 1000,
30	  amulet: 600,
31	  staff: 800,
32	  potion: 400,
33	  rune: 250,
34	  moonstone: 250,
35	};
36	
37	const CAP_MULTIPLIER = 2;
38	
39	function computeInsuranceSum(items: Array<Item>): number {
40	  return items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
41	}
42	
43	function withFirstInsuranceSurcharge(basePremium: number): number {
44	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
45	}
46	
47	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
48	  return condition ? basePremium * rate : 0;
49	}
50	
51	function hasEnchantmentAtLeast(item: Item | undefined, threshold: number): boolean {
52	  return (item?.enchantment ?? 0) >= threshold;
53	}
54	
55	function getBasePremium(itemType: string): number {
56	  const basePremium = BASE_PREMIUMS[itemType];
57	  if (basePremium === undefined) {
58	    throw new Error(`Unknown item type: ${itemType}`);
59	  }
60	  return basePremium;
61	}
62	
63	function quoteItem(item: Item): number {
64	  const basePremium = getBasePremium(item.type);
65	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
66	  const highEnchantmentSurcharge = surchargeIf(
67	    hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD),
68	    basePremium,
69	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	  );
71	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
72	}
