77	function countByType(items: Array<Item>): Record<string, number> {
78	  const counts: Record<string, number> = {};
79	  for (const item of items) {
80	    counts[item.type] = (counts[item.type] ?? 0) + 1;
81	  }
82	  return counts;
83	}
84	
85	function isLoyalCustomer(customer: Customer | undefined): boolean {
86	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
87	}
88	
89	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
90	  const counts = countByType(items);
91	  let itemsPremium = 0;
92	  let sumOfBases = 0;
93	  const bundledTypes = new Set<string>();
94	
95	  for (const componentType of COMPONENT_TYPES) {
96	    if (counts[componentType] === 3) {
97	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
98	      sumOfBases += BLOCK_OF_THREE_BASE;
99	      bundledTypes.add(componentType);
100	    }
101	  }
102	
103	  for (const item of items) {
104	    if (bundledTypes.has(item.type)) continue;
105	    itemsPremium += quoteItem(item);
106	    sumOfBases += getBasePremium(item.type);
107	  }
108	
109	  return { itemsPremium, sumOfBases };
110	}
111	
112	type Policy = { items: Array<Item>; capRemaining: number };
113	
114	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
115	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
116	
117	function computeDamagePayout(damage: Damage, policy: Policy | undefined): number {
118	  const item = policy?.items.find((i) => i.type === damage.itemType);
119	  const reimbursableAmount = hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
120	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
121	    : damage.amount;
122	  return Math.max(0, reimbursableAmount - DEDUCTIBLE_PER_DAMAGE);
123	}
124	
125	function computePayout(incident: Incident | undefined, policy: Policy | undefined): number {
126	  const damages = incident?.damages ?? [];
127	  return damages.reduce((total, damage) => total + computeDamagePayout(damage, policy), 0);
128	}
129	
130	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
131	
132	function assertDamageAmountIsNonNegative(damage: Damage): void {
133	  if (damage.amount < 0) {
134	    throw new Error(`Negative damage amount: ${damage.amount}`);
135	  }
136	}
137	
138	function assertDamageIsCoveredByPolicy(damage: Damage, policy: Policy | undefined): void {
139	  if (!policy?.items.some((item) => item.type === damage.itemType)) {
140	    throw new Error(`Item type not in policy: ${damage.itemType}`);
141	  }
142	}
143	
144	function assertDamagesAreValid(incident: Incident | undefined, policy: Policy | undefined): void {
145	  const damages = incident?.damages ?? [];
146	  for (const damage of damages) {
147	    assertDamageAmountIsNonNegative(damage);
148	    assertDamageIsCoveredByPolicy(damage, policy);
149	  }
150	}
151	
152	function handleClaim(step: Step, policies: Map<number, Policy>): StepResult {
153	  const policy = policies.get(step.policy ?? 0);
154	  assertDamagesAreValid(step.incident, policy);
155	  const desired = Math.floor(computePayout(step.incident, policy));
156	  const capRemaining = policy?.capRemaining ?? Infinity;
157	  const actualPayout = Math.min(desired, capRemaining);
158	  const newCapRemaining = capRemaining - actualPayout;
159	  if (policy) policy.capRemaining = newCapRemaining;
160	  return { payout: actualPayout, remainingCap: newCapRemaining };
161	}
162	
163	function handleQuote(
164	  step: Step,
165	  stepIndex: number,
166	  customer: Customer | undefined,
167	  policies: Map<number, Policy>,
168	): StepResult {
169	  const items = step.items ?? [];
170	  policies.set(stepIndex, {
171	    items,
172	    capRemaining: CAP_MULTIPLIER * computeInsuranceSum(items),
173	  });
174	  const { itemsPremium, sumOfBases } = quoteItems(items);
175	  const loyaltyDiscount = isLoyalCustomer(customer) ? sumOfBases * LOYALTY_DISCOUNT_RATE : 0;
176	  const followUpDiscount = stepIndex >= 1 ? sumOfBases * FOLLOWUP_DISCOUNT_RATE : 0;
177	  const premium = Math.ceil(itemsPremium - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
178	  return { premium };
179	}
180	
181	export function processScenario(scenario: unknown): { results: Array<StepResult> } {
182	  const { customer, steps } = scenario as Scenario;
183	  const policies = new Map<number, Policy>();
184	  const results = steps.map((step, stepIndex) =>
185	    step.op === "claim"
186	      ? handleClaim(step, policies)
187	      : handleQuote(step, stepIndex, customer, policies),
188	  );
189	  return { results };
190	}
